"""
MKT Christ — Luke all 24 chapters
Output: data/commentary/mkt-christ/luke.json
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

DATA = {
  "1": {
    "46": '<p>A type: the Magnificat. Mary\'s song is shaped by Hannah\'s prayer (1 Sam 2:1-10) — Hannah as the type of the Spirit-filled woman through whom the Lord\'s anointed enters the world. But the Magnificat exceeds Hannah\'s song: where Hannah praised for her personal vindication, Mary praises for the eschatological reversal that the incarnation initiates for all the humble and hungry of Israel and the world. The type (Hannah/Samuel) points to the antitype (Mary/Jesus) not as mere parallel but as fulfillment: what Hannah\'s prayer anticipated (the exaltation of the humble, the strength of the LORD\'s anointed) is now the content of the incarnation itself.</p>',
    "68": '<p>A fulfillment: blessed be the Lord God of Israel, for he has visited and redeemed his people. Zechariah\'s Benedictus identifies the births of John and Jesus as the visitation (episkope) of YHWH that all the prophets promised. The OT motif of divine visitation (YHWH visiting his people in mercy or judgment) reaches its fulfillment in the incarnation: God personally visits his people not through a prophet or angel but in the person of his Son. The redemption (lytrosis, v.68; lytrosan, v.74) is the Exodus-liberation pattern now applied to redemption from enemies (political) and from sin (spiritual), with both dimensions present.</p>'
  },
  "2": {
    "11": '<p>A direct revelation: a Savior, who is Christ the Lord, has been born for you in the city of David. The angelic announcement at the shepherds concentrates Luke\'s Christology in a single sentence. The Savior born in David\'s city is the fulfillment of the Davidic covenant, the messianic hope, and the divine rescue promised throughout the OT. Luke\'s characteristic soter (Savior) title connects Jesus to the salvation history of Israel (YHWH as Israel\'s only savior, Isa 43:11) while the details of the manger, the shepherds, and the town of Bethlehem anchor the salvation in the most ordinary and humble circumstances — the divine Savior in a feeding trough.</p>',
    "32": '<p>A fulfillment: a light for revelation to the Gentiles and for glory to your people Israel. Simeon\'s Nunc Dimittis applies the Isaianic Servant vocation (Isa 49:6) to the infant Jesus: he is the Servant who is a light to the nations. Luke\'s Gospel will be the narrative of this dual fulfillment — the glory of Israel (through the Jewish mission) and the light to the Gentiles (through the Gentile mission that Acts continues). The infant who cannot yet speak is already identified as the one in whom the universal Servant mission will be embodied and accomplished.</p>'
  },
  "4": {
    "18": '<p>A direct revelation: the Spirit of the Lord is upon me, because he has anointed me to proclaim good news to the poor. The Nazareth synagogue scene is Luke\'s programmatic statement of the Christological mission. Jesus reads Isa 61:1-2 and declares today this scripture has been fulfilled in your hearing (v.21) — the most explicit self-identification with the Isaianic Servant in the Synoptic Gospels. Luke presents the Christ\'s mission as the Jubilee: release to captives (from sin and from evil powers), sight to the blind, freedom for the oppressed, the year of the Lord\'s favor. The entire Gospel is the unfolding of this Jubilee-mission.</p>',
    "43": '<p>A direct revelation: I must preach the good news of the kingdom of God to the other towns as well; for I was sent for this purpose. The dei (it is necessary) of v.43 is one of Luke\'s most important theological terms — divine necessity shapes the mission at every point. Jesus was sent (apestalen) — the mission is not self-chosen but given by the Father. The kingdom of God that Jesus preaches is the reign of God becoming present in his own person; to hear Jesus is to encounter the kingdom\'s arrival.</p>'
  },
  "7": {
    "22": '<p>A fulfillment: go and tell John what you have seen and heard — the blind receive their sight, the lame walk, lepers are cleansed, the deaf hear, the dead are raised, the poor have good news proclaimed. Jesus\'s answer to the imprisoned John is the definitive self-identification from Isaiah: the signs that he lists are precisely the signs that Isaiah promised when YHWH comes to save (Isa 35:5-6, 61:1). Christ\'s identity is proven not by Messianic title-claim but by Isaianic sign-fulfillment; the question is not what do you claim to be? but what do you see happening? The works are the revelation.</p>'
  },
  "9": {
    "51": '<p>A direct revelation: when the days drew near for him to be taken up, he set his face to go to Jerusalem. Luke\'s travel-narrative framing (9:51-19:44) presents the entire journey to Jerusalem as a deliberate movement toward the passion, resurrection, and ascension. Jesus does not drift toward Jerusalem; he sets his face (Isa 50:7, the Servant who sets his face like flint to face opposition). Every parable and teaching in the travel narrative is colored by this deliberate journey toward the cross. The Christological claim is implicit: the one who moves with this resolve toward his own death is the one who has freely accepted the Father\'s mission from eternity.</p>'
  },
  "15": {
    "20": '<p>A revelation of God: the father of the prodigal son runs, embraces, and restores without condition. The father in the parable is transparently the image of God — no other first-century Jewish father would run (an undignified act) to embrace a disgraced son before any apology had been given. The parable is Jesus\'s defense of his own practice (receiving sinners) by revealing the Father\'s character: God himself is the running father who hosts the party for the found son and pleads with the older brother. Every feature of the father\'s excess (running, robe, ring, sandals, feast, self-humiliation at the party\'s edge) is a portrait of divine grace preceding, enabling, and exceeding human repentance.</p>'
  },
  "19": {
    "10": '<p>A direct revelation: the Son of Man came to seek and to save the lost. Luke\'s mission-statement frames the Zacchaeus encounter as the paradigmatic instance of the Son of Man\'s seeking-saving mission. The three parables of Luke 15 and the Zacchaeus narrative are the lived theology of Luke 19:10: the lost sheep sought by the shepherd, the lost coin sought by the woman, the lost son welcomed by the father, and now the lost Zacchaeus sought-and-found by the Son of Man himself. The mission of Luke\'s Gospel is the living-out of this one sentence, fulfilled supremely in the cross (where the Son of Man gives himself to save the utterly lost).</p>'
  },
  "22": {
    "20": '<p>A fulfillment: this cup that is poured out for you is the new covenant in my blood. Luke\'s cup-word (with the new covenant language from Jer 31:31-34) is the most explicit Jeremianic citation in the passion narratives. The new covenant — written on the heart, bringing forgiveness of sins, creating universal knowledge of YHWH — is inaugurated in the cup of Jesus\'s blood. The Passover context connects the new covenant blood to the Exodus blood (the lamb\'s blood that protected from the destroying angel): Christ\'s blood is simultaneously the final Passover (ending the old covenant\'s provisional atonement) and the new covenant\'s ratifying sacrifice.</p>',
    "37": '<p>A fulfillment: this scripture must be fulfilled in me: And he was numbered with the transgressors. Jesus\'s citation of Isa 53:12 before his arrest is the clearest evidence in the Synoptics that Jesus explicitly understood his death as the fulfillment of the Servant\'s vicarious suffering. The verb dei (must be fulfilled) indicates divine necessity: the Servant\'s path of bearing sin for the many was not merely predictive of his death but constitutive of the divine plan from which the cross received its saving power. The numbered-with-transgressors (arrested as a criminal) is the humiliation that precedes the Servant\'s exaltation.</p>'
  },
  "23": {
    "43": '<p>A direct revelation: today you will be with me in paradise. The word to the penitent criminal is the most compressed eschatological promise in the Gospels: today (the dying day, no purgatorial delay), with me (personal presence with Christ, not merely a blessed state), in paradise (the garden-restored, the original Eden-with-God now restored). The dying Christ who is in the process of bearing sin for the many simultaneously promises the thief immediate eschatological fellowship. The promise grounds the community\'s confidence: if even the dying criminal is welcomed today, the resurrection-hope of all who trust Christ is secured.</p>',
    "46": '<p>A direct revelation: Father, into your hands I commit my spirit. Luke\'s Christ dies with Ps 31:5 as his final prayer — the trust-language of the righteous sufferer who commits himself to the faithful Father at death. The Father-address maintains the intimate relationship that defined the whole of Luke\'s Christological portrayal (Abba in Gethsemane, 22:42; this prayer at death). The Spirit commended to the Father\'s hands is the Spirit that will be poured out at Pentecost (Acts 2) — even in death the Son\'s Spirit remains in the Father\'s keeping, to be given back in the resurrection and then poured out on the community.</p>'
  },
  "24": {
    "27": '<p>A direct revelation: beginning with Moses and all the Prophets he interpreted to them in all the Scriptures the things concerning himself. The risen Christ\'s Emmaus hermeneutic is the epistemological key to Luke\'s entire Gospel: the OT is about Christ, and only the risen Christ can unlock its true meaning. The burning hearts (v.32) indicate that proper reading of Scripture is simultaneously encounter with the risen Christ — not merely information about him but the experience of his presence through the word. Luke\'s Gospel has been narrating what the risen Christ explained: the whole story of Israel (from Genesis through the Prophets) was the long preparation for and anticipation of what Jesus accomplished in Jerusalem.</p>',
    "46": '<p>A direct revelation: it is necessary that the Christ should suffer and on the third day rise from the dead, and that repentance for the forgiveness of sins should be proclaimed in his name to all nations. The risen Christ\'s final hermeneutical statement to the disciples declares the canonical shape of the Christological narrative: suffering → resurrection is the divinely necessary arc (dei), and the worldwide mission to proclaim forgiveness in his name is its equally necessary consequence. Luke 24:46-47 is the theological thesis of Acts, which will narrate exactly this proclamation going from Jerusalem to the ends of the earth. The Christ\'s mission is complete; the community\'s mission is just beginning.'
  }
}

FILL_CH22 = {
  "22": {
    "1": "<p>A type: the approaching Festival of Unleavened Bread is the liturgical frame within which Christ will become the final Passover lamb. Luke names the feast to anchor Jesus&#8217;s death in Israel&#8217;s redemption calendar&#8212;the paschal lamb slaughtered, the blood applied, Israel delivered. Every Passover since Sinai was a type of this one; this one ends the typological sequence by fulfilling what all the lambs signified.</p>",
    "2": "<p>A theme: the chief priests and scribes seeking to destroy Jesus enact the pattern of Israel rejecting its prophets and its King (Lk 13:34). Their fear of the people is the political face of the deeper reality: the rulers of this age did not recognize the Lord of glory and so crucified him (1 Cor 2:8). Official Israel&#8217;s opposition is simultaneously the mechanism of the world&#8217;s redemption.</p>",
    "3": "<p>A theme: Satan entering Judas reveals the cosmic dimension of the passion&#8212;the cross is not merely a political execution but the direct confrontation between Christ and the powers of darkness. Luke bookends the temptation (4:13, &#8220;until an opportune time&#8221;) and the betrayal (22:3) with Satan&#8217;s activity; the passion is the opportune time Satan had been waiting for. Christ enters this darkness voluntarily (v.53: &#8220;your hour, and the power of darkness&#8221;).</p>",
    "4": "<p>A fulfillment: Judas negotiating the betrayal with the chief priests enacts Ps 41:9&#8212;&#8220;even my close friend in whom I trusted, who ate my bread, has lifted his heel against me.&#8221; The one who reclines at table with Jesus and receives the bread (vv.14&#8211;23) becomes the instrument of his arrest. The type (David betrayed by Ahithophel) reaches its antitype in the Son of Man betrayed by one of the Twelve.</p>",
    "5": "<p>A theme: the leaders&#8217; delight at finding a willing betrayer among Jesus&#8217;s own disciples marks the depth of the opposition. The transaction reduces the Son of God to a commodity&#8212;the Lord of glory priced and sold. Matthew records the thirty pieces of silver (fulfilling Zech 11:12), but Luke&#8217;s spare account focuses on the consent: the betrayal is willing from both sides.</p>",
    "6": "<p>A theme: Judas watching for an opportunity to betray Jesus away from the crowd mirrors the deliberate, patient opposition of those who reject the Christ. His caution&#8212;avoiding the crowd that would defend Jesus&#8212;shows that the rejection of the Son of God is not impulsive but calculated. The hour of darkness (v.53) approaches through this patient plotting.</p>",
    "7": "<p>A type: &#8220;the day when the Passover lamb had to be sacrificed&#8221; is Luke&#8217;s announcement that the typological moment has arrived. The Passover lamb&#8212;unblemished, killed at twilight, its blood protecting from death&#8212;is the central OT type of Christ&#8217;s atoning sacrifice (1 Cor 5:7, &#8220;Christ our Passover lamb has been sacrificed&#8221;). Every detail of the Passover ordinance finds its fulfillment in what Jesus is about to accomplish.</p>",
    "8": "<p>A type: Jesus directing Peter and John to prepare the Passover shows him actively orchestrating the final Passover&#8212;not a victim but the purposeful priest and lamb in one. He sends his disciples to prepare the feast in which he himself will be the sacrifice. The one who commands the preparation is the one who will be broken and poured out at the table.</p>",
    "9": "<p>A theme: the disciples&#8217; question&#8212;&#8220;where do you want us to prepare?&#8221;&#8212;is the obedient posture of those learning to follow Christ&#8217;s direction even without full understanding. The unknown upper room, reached through a providential sign, teaches that the community of the new covenant depends entirely on Christ&#8217;s initiative and provision.</p>",
    "10": "<p>A theme: the sign of the man carrying a water jar and the instructions that follow reveal Christ&#8217;s prophetic foreknowledge ordering every detail of the final Passover. His sovereignty over the logistics of his own last supper signals the same sovereignty that will govern the passion, resurrection, and mission that follow. Nothing in the sequence of redemption happens by accident.</p>",
    "11": "<p>A type: &#8220;the Teacher asks: where is the guest room where I may eat the Passover with my disciples?&#8221;&#8212;the Son of God, the eternal host of all heavenly feasting, requiring borrowed space to eat his last meal. The lowliness is itself the revelation: the one who prepares the eternal banquet has no room of his own in the city of David.</p>",
    "12": "<p>A theme: the large, furnished upper room provided without prior arrangement confirms Christ&#8217;s foreknowledge and the Father&#8217;s providential preparation. Every need for the final Passover is met before it is felt; the community of the new covenant will find that the same provision governs the mission entrusted to them after the resurrection.</p>",
    "13": "<p>A theme: &#8220;they found things just as Jesus had told them&#8221; is Luke&#8217;s recurring verification formula&#8212;the word of Christ reliably anticipates and governs reality. The disciples who prepare the Passover according to Christ&#8217;s word are practicing the obedient faith that the new covenant community will need in every generation: trust the word, find it true.</p>",
    "14": "<p>A direct revelation: the hour arrived and Jesus reclined with his apostles&#8212;the Son of God at table with his chosen community on the eve of the sacrifice that will ratify the new covenant. The reclining posture is the posture of the Passover Seder (freed persons recline, not slaves), yet within hours the host will be arrested, tried, and crucified. The Last Supper holds together the freedom of the feast and the cost of the sacrifice.</p>",
    "15": "<p>A direct revelation: &#8220;I have eagerly desired to eat this Passover with you before I suffer.&#8221; Christ&#8217;s own words frame the Last Supper as the deliberate threshold of the passion. His eagerness is not resignation but the purposeful desire of the Servant who embraces the cup (Isa 53:10&#8212;&#8220;it was the will of the LORD to crush him&#8221;). The suffering that follows is not a tragedy that overtakes him but the mission he has come to accomplish.</p>",
    "16": "<p>A type: &#8220;I will not eat it again until it finds fulfillment in the kingdom of God&#8221; declares that the Passover itself is a type waiting for its eschatological antitype. The new Passover&#8212;the Eucharist&#8212;is itself a foretaste of the messianic banquet (Isa 25:6&#8211;8) when Christ eats and drinks with his redeemed community in the fully-arrived kingdom. Every celebration of the Lord&#8217;s Supper points forward to that final feast.</p>",
    "17": "<p>A type: Jesus taking the Passover cup and giving thanks connects the Last Supper to the Passover liturgy&#8212;the cups of the Seder rehearsed Israel&#8217;s redemption. This cup before the bread institution anticipates the covenant cup (v.20) that follows; Luke&#8217;s account presents the movement from Passover-remembrance to new covenant inauguration as a deliberate, ordered sequence.</p>",
    "18": "<p>A theme: &#8220;I will not drink again from the fruit of the vine until the kingdom of God comes&#8221; sets the Last Supper at the hinge of the ages. Christ&#8217;s abstinence after this point marks the end of the old age&#8217;s feasting and the beginning of the cross; his drinking again in the kingdom marks the resurrection-age. The Eucharist in every generation is celebrated in the space between these two: after the cross, before the consummation.</p>",
    "19": "<p>A direct revelation: &#8220;this is my body given for you; do this in remembrance of me.&#8221; The bread broken and distributed is Christ&#8217;s own body&#8212;his life given for his people&#8217;s life. The institution of the Eucharist is the clearest statement in Luke&#8217;s Gospel that Christ&#8217;s death is substitutionary gift: his body is given so that theirs might be preserved. The command to &#8220;do this&#8221; in remembrance makes every subsequent Eucharist a proclamation of the Lord&#8217;s death until he comes (1 Cor 11:26).</p>",
    "21": "<p>A fulfillment: the betrayer&#8217;s hand on the table while Jesus speaks of his body and blood given for them fulfills Ps 41:9&#8212;&#8220;my close friend who ate my bread has lifted his heel against me.&#8221; The intimacy of the table is the intimacy of the betrayal. David&#8217;s experience with Ahithophel was the type; the Son of Man betrayed by a table-companion is the antitype that gives the psalm its deepest meaning.</p>",
    "22": "<p>A direct revelation: &#8220;the Son of Man goes as it has been decreed, but woe to that man who betrays him.&#8221; The divine decree (dei) governs the passion without removing Judas&#8217;s culpability. The cross is simultaneously the fulfillment of the eternal plan and the act of human wickedness; both are true without the one eliminating the other. Christ names both realities in the same breath.</p>",
    "23": "<p>A theme: the disciples questioning which of them would betray Jesus reveals their incomprehension of the gravity of what Jesus has announced. They cannot conceive that one of them is the betrayer&#8212;the same incomprehension that will lead them to sleep in Gethsemane and flee at the arrest. The community that gathers around the Lord&#8217;s table always risks self-deception about its own fidelity.</p>",
    "24": "<p>A revelation of God: a dispute about greatness erupts immediately after the institution of the Eucharist. Christ&#8217;s response (vv.25&#8211;27) reveals the character of God&#8217;s kingdom by pointing to his own incarnate servanthood: &#8220;I am among you as one who serves&#8221; (v.27). The God who takes flesh to serve and die is the definitive inversion of all human hierarchies; the community formed by his table exists to embody this inversion.</p>",
    "25": "<p>A theme: &#8220;the kings of the Gentiles lord it over them, and those in authority are called benefactors.&#8221; Jesus identifies the worldly pattern&#8212;power exercised as domination, domination dressed as generosity&#8212;and refuses it entirely for the kingdom community. The Gentile pattern of benefactor-lordship is the precise opposite of the self-giving service that Christ&#8217;s own death will demonstrate.</p>",
    "26": "<p>A direct revelation: &#8220;the greatest among you should be like the youngest, and the one who leads like the one who serves.&#8221; Christ redefines greatness by his own person: the one who is greatest (the Son of God) becomes the youngest in rank (the servant of all). Kingdom authority flows downward in service, not upward in domination. The disciples are to embody what the incarnation demonstrates.</p>",
    "27": "<p>A direct revelation of God: &#8220;I am among you as one who serves.&#8221; The Son of God, at the table he has prepared for his disciples, identifies himself as the servant rather than the host in the worldly sense. This is the Christological foundation of Christian ethics: servanthood is not a virtue imposed from outside but the imitation of the one who is among them serving. The Eucharistic table is the school of servant-leadership.</p>",
    "28": "<p>A theme: Jesus&#8217;s recognition&#8212;&#8220;you have stood by me in my trials&#8221;&#8212;honors the disciples&#8217; partial and imperfect faithfulness even as they are about to fail dramatically. The faithfulness Christ honors is not their future performance (which will be dismal) but their present attachment. Grace precedes and enables the faithfulness it eventually produces.</p>",
    "29": "<p>A direct revelation: &#8220;I confer on you a kingdom, just as my Father conferred one on me.&#8221; The Davidic covenant reaches its fulfillment: the Father confers the kingdom on the Son (Ps 2:6&#8211;8; Dan 7:13&#8211;14), and the Son extends that kingdom-authority to his apostolic community. The disciples who will sit on thrones (v.30) receive their authority entirely from Christ&#8217;s mediation of the Father&#8217;s gift.</p>",
    "30": "<p>A type: eating and drinking at Christ&#8217;s table in the kingdom and sitting on thrones judging the twelve tribes points to the eschatological messianic banquet (Isa 25:6&#8211;8) and the restored-Israel judgment (Dan 7:22). The twelve apostles as judges of the twelve tribes signals that the new covenant community is the eschatological Israel&#8212;the fulfillment of the covenant people whose leaders are appointed by the Messiah himself.</p>",
    "31": "<p>A theme: &#8220;Satan has asked to sift all of you as wheat&#8221;&#8212;the cosmic adversary seeks to destroy the disciples&#8217; faith through the coming crisis of the passion. The sifting image echoes Job&#8217;s trial (permitted by God, aimed at destruction, turned toward vindication). Christ&#8217;s prior knowledge of Satan&#8217;s request reveals that the passion is not a surprised response to evil but a governed unfolding within the Father&#8217;s sovereign permission.</p>",
    "32": "<p>A direct revelation: &#8220;I have prayed for you, Simon, that your faith may not fail.&#8221; Christ&#8217;s high-priestly intercession for Peter before the denial is the ground of Peter&#8217;s restoration after it. The prayer is not that Peter will not fall&#8212;he will&#8212;but that his faith will ultimately survive. The &#8220;when you have turned back&#8221; is Christ&#8217;s own foreknowledge-based confidence in the efficacy of his intercession; Peter&#8217;s restoration is secured by Christ&#8217;s prayer, not Peter&#8217;s strength.</p>",
    "33": "<p>A theme: Peter&#8217;s confident declaration&#8212;&#8220;I am ready to go with you to prison and to death&#8221;&#8212;is the overconfidence that precedes the fall. The gap between Peter&#8217;s self-assessment and his actual capacity reveals the human inability to sustain faithfulness through crisis by willpower alone. The intercession Christ has just offered (v.32) is precisely what Peter&#8217;s self-confidence cannot supply.</p>",
    "34": "<p>A direct revelation: Christ&#8217;s prophecy of the triple denial&#8212;with the specific detail of the rooster crowing&#8212;demonstrates his prophetic foreknowledge and validates the intercession he has just made. The prophecy is not condemnation but instruction: Peter&#8217;s denial will happen exactly as Christ said, and when the rooster crows Peter will remember the word of the Lord (v.61) and be turned back to the one who prayed for him.</p>",
    "35": "<p>A theme: the contrast between the earlier mission (sent without purse or bag, lacking nothing) and the coming crisis signals that the disciples are entering a fundamentally different phase. The earlier period of miraculous provision is not repealed but expanded into a harder context: they must now be prepared for opposition, rejection, and the full weight of the mission beyond the initial Galilean success.</p>",
    "36": "<p>A theme: &#8220;but now&#8221;&#8212;the phrase marks the decisive turn. The changed instructions (take purse, bag, and if necessary a sword) signal that the hour of the passion has arrived and the mission context has changed. Christ is not commanding armed resistance (v.51 proves this) but communicating the gravity of what they are about to face; the era of easy reception is over, and the cross-shaped mission begins.</p>",
    "38": "<p>A theme: &#8220;that is enough!&#8221;&#8212;Christ&#8217;s gentle rebuke stops the disciples&#8217; literalistic counting of swords. They have missed the point entirely: he is describing the changed hour of the passion, not organizing an armed defense. The disciples&#8217; persistent misreading of Christ&#8217;s kingdom as a political-military project reaches its final correction in the garden (v.51) when Christ heals the wounded servant.</p>",
    "39": "<p>A type: Christ going as usual to the Mount of Olives signals that Gethsemane is not a crisis but a habitual practice&#8212;his prayer life was already shaped by this place of withdrawal. The Mount of Olives (pressing place) is the fitting location for the agony that follows. His disciples follow him, as they have throughout the journey, into a place they will not be able to endure with him.</p>",
    "40": "<p>A theme: &#8220;pray that you will not fall into temptation&#8221;&#8212;Christ&#8217;s instruction to his disciples before his own prayer reveals his pastoral concern even in extremity. The same temptation that will overwhelm the disciples (they will sleep, flee, and deny) is the one he is about to face and overcome. His instruction points to the only remedy: prayer, which they will fail to sustain.</p>",
    "41": "<p>A direct revelation: Christ withdrawing and kneeling to pray is the incarnate Son in the posture of creaturely dependence before the Father. The one who is equal with God (Phil 2:6) takes the posture of a suppliant; the eternal Son expresses his humanity through prayer. Gethsemane is the proof that Christ&#8217;s suffering is real human suffering, not docetic performance.</p>",
    "42": "<p>A direct revelation of God: &#8220;Father, if you are willing, take this cup from me; yet not my will, but yours be done.&#8221; The cup is the OT cup of divine wrath (Jer 25:15&#8211;17; Ps 75:8) that the Son is about to drain for his people. The prayer&#8217;s two movements&#8212;honest human petition followed by perfect filial submission&#8212;reveal the Son&#8217;s full humanity (he dreads the cup) and full obedience (he accepts the Father&#8217;s will). This is the moment the new covenant sacrifice is freely offered.</p>",
    "43": "<p>A theme: the angel strengthening Christ in Gethsemane is the Father&#8217;s answer to the Son&#8217;s prayer&#8212;not by removing the cup but by sustaining him to drink it. The angels who ministered to him after the temptation (implied in Lk 4:13) now minister again at the passion&#8217;s threshold. Christ&#8217;s humanity is real enough to require strengthening; his obedience is strong enough to continue through the anguish.</p>",
    "44": "<p>A direct revelation: &#8220;being in anguish, he prayed more earnestly, and his sweat was like drops of blood.&#8221; The intensity of Christ&#8217;s Gethsemane agony is not fear of physical suffering but the weight of bearing the sin of the world. The more earnest prayer and the blood-like sweat reveal a anguish that goes beyond what any martyr faces at death&#8212;this is the Servant taking on the iniquity of all (Isa 53:6), and the weight of it is physically felt.</p>",
    "45": "<p>A theme: the disciples asleep from sorrow could not watch one hour with Christ in his hour of need. Their sorrow is real but insufficient&#8212;they are overwhelmed by grief rather than sustained by prayer. The contrast between Christ who prays more earnestly under pressure and disciples who collapse into sleep defines the gap between the Christ who saves and the humanity he saves.</p>",
    "46": "<p>A theme: &#8220;get up and pray so that you will not fall into temptation&#8221;&#8212;Christ&#8217;s second instruction to the sleeping disciples is the same as his first (v.40), showing that his pastoral concern for them persists through his own extremity. His instruction is also his example: he has just prayed through his own temptation to evade the cup. The disciples who will not pray will fall; the Christ who prayed will not.</p>",
    "47": "<p>A fulfillment: Judas leading the crowd to betray Jesus with a kiss fulfills Ps 41:9 at its most precise&#8212;the close friend whose bread was shared (v.21) approaches with the greeting of intimacy turned to treachery. The kiss is the supreme irony of the passion: the gesture of love and welcome becomes the instrument of arrest and death.</p>",
    "48": "<p>A direct revelation: &#8220;Judas, are you betraying the Son of Man with a kiss?&#8221; Christ names both the act and his own identity in the question. He does not hide from the betrayal or resist the arrest; he names what is happening clearly, identifying himself as the Son of Man (Dan 7:13&#8211;14) even as he is surrendered to human power. The question is both pastoral and judicial: it gives Judas one final moment of hearing his name from the Son of Man.</p>",
    "49": "<p>A theme: &#8220;Lord, should we strike with our swords?&#8221;&#8212;the disciples&#8217; question at the arrest is the final evidence of their failure to understand Christ&#8217;s kingdom. Throughout the Gospel they have misconstrued his mission as political-military; at the moment of crisis they reach for the weapons. Christ&#8217;s healing response (v.51) is the definitive correction.</p>",
    "50": "<p>A theme: one of the disciples cutting off the servant&#8217;s ear enacts exactly the violence Christ has forbidden (vv.35&#8211;38) and the misunderstanding of the kingdom he has repeatedly corrected. The wound is immediately healed (v.51); Christ&#8217;s last miracle before the cross is an act of mercy toward an agent of his own arrest.</p>",
    "51": "<p>A direct revelation of God: &#8220;no more of this!&#8221; and the healing of the ear reveals the character of the Christ who is being arrested. He refuses armed defense, heals the enemy, and submits to the unjust arrest&#8212;not because he is powerless but because this is how the Son of God accomplishes redemption. The healing is a sign: the kingdom this Christ brings heals rather than wounds, even at the cost of his own life.</p>",
    "52": "<p>A direct revelation: Christ confronting the chief priests, temple officers, and elders who come armed with swords and clubs exposes the absurdity of their approach. His daily teaching in the temple (v.53) was utterly peaceful; the armed arrest at night reveals their fear of truth, not their power over him. He goes with them not because they have captured him but because he has chosen the hour.</p>",
    "53": "<p>A direct revelation of God: &#8220;this is your hour&#8212;when darkness reigns.&#8221; Christ identifies the arrest not as the victory of his enemies but as the appointed hour when the power of darkness is permitted its apparent triumph. The cross is God&#8217;s sovereign use of evil&#8217;s darkest hour to accomplish the world&#8217;s redemption. Satan&#8217;s hour of apparent power is simultaneously the hour of his defeat (Col 2:15).</p>",
    "54": "<p>A theme: &#8220;Peter followed at a distance&#8221;&#8212;the distance is already the beginning of the denial. The one who said he would go to prison and death cannot close the gap between himself and the arrested Lord. The distance is both physical and spiritual: Peter is near enough to be recognized, far enough to deny. Christ&#8217;s intercession (v.32) is the only thing that will eventually close the gap.</p>",
    "55": "<p>A theme: Peter sitting among the fire-warmers in the courtyard of the high priest&#8217;s house is the dangerous proximity that will cost him. He has not fled like the others, which is credit to his love; but he sits among the enemies, which is the risk his courage cannot sustain. The fire&#8217;s light is what makes the denial possible: it reveals his face to the servant girl.</p>",
    "56": "<p>A theme: &#8220;this man was with him&#8221;&#8212;the servant girl&#8217;s identification of Peter is the first test of his confession. The phrase &#8220;was with him&#8221; is the language of discipleship; to deny it is to deny the defining fact of his identity. Peter&#8217;s response (&#8220;I don&#8217;t know him&#8221;) is the inversion of Christ&#8217;s confession at the Sanhedrin (v.70)&#8212;where Christ will affirm his identity under pressure, Peter denies his.</p>",
    "57": "<p>A fulfillment: &#8220;woman, I don&#8217;t know him&#8221;&#8212;the first denial fulfills Christ&#8217;s prophecy of v.34 exactly. Peter&#8217;s denial is not abstract apostasy but the specific, named refusal of the relationship that has defined three years of his life. The one who was ready to go to prison and death cannot sustain his confession by a courtyard fire.</p>",
    "58": "<p>A fulfillment: the second denial&#8212;&#8220;man, I am not!&#8221;&#8212;continues the fulfillment of Christ&#8217;s prophecy. Each denial deepens the distance Peter is creating between himself and the arrested Lord. The progression from &#8220;I don&#8217;t know him&#8221; to &#8220;I am not&#8221; mirrors the progressive self-erasure of anyone who disowns their identity in Christ under social pressure.</p>",
    "59": "<p>A fulfillment: the third identification&#8212;&#8220;certainly this fellow was with him, for he is a Galilean&#8221;&#8212;presses Peter with his unmistakable regional accent. The certainty of the accusation matches the certainty of the denial and the certainty of Christ&#8217;s prophecy. Peter&#8217;s Galilean identity, which once marked him as a disciple of the Galilean teacher, now marks him as a liability.</p>",
    "60": "<p>A fulfillment: &#8220;I don&#8217;t know what you&#8217;re talking about!&#8221; and immediately the rooster crowed&#8212;the third denial and the fulfillment of Christ&#8217;s word to the syllable (v.34). The rooster&#8217;s crow is the Father&#8217;s alarm clock for Peter: the word of the Lord, once spoken, governs reality and will not return empty. Even in Peter&#8217;s failure the faithfulness of Christ&#8217;s word is demonstrated.</p>",
    "61": "<p>A direct revelation of God: &#8220;the Lord turned and looked straight at Peter.&#8221; Across the courtyard, the arrested Christ looks at the denying Peter&#8212;and the look breaks him. This is the look of the one who prayed for him (v.32), who knew the denial would come, who has loved him through it. The look is not accusation but recognition&#8212;I know you, I prayed for you, now remember. It is the gaze of the Shepherd who never loses sight of the straying sheep.</p>",
    "62": "<p>A theme: Peter going outside and weeping bitterly is the repentance that Christ&#8217;s intercession (v.32) was designed to produce. The tears distinguish Peter&#8217;s response from Judas&#8217;s remorse (Matt 27:3&#8211;5): both feel the weight of what they have done, but Peter&#8217;s grief leads to restoration while Judas&#8217;s leads to destruction. The difference is not the depth of the sorrow but the direction it moves&#8212;toward or away from the one who still prays for the sinner.</p>",
    "63": "<p>A fulfillment: the guards mocking and beating Jesus fulfill Isa 50:6&#8212;&#8220;I gave my back to those who strike, and my cheeks to those who pull out the beard; I hid not my face from disgrace and spitting.&#8221; The third Servant Song anticipates exactly this: the Servant submitted to humiliation without resistance because he trusted the Lord who would vindicate him. The abuse in the courtyard is the typological scene enacted.</p>",
    "64": "<p>A fulfillment: &#8220;prophesy! who hit you?&#8221;&#8212;the mockery of the blindfolded Jesus as a prophet is deeply ironic. The one they are taunting to prophesy has just fulfilled three prophecies in the space of hours (the Passover room, Peter&#8217;s denial, the betrayal). Their blindfold cannot prevent him from seeing; their mockery cannot diminish the prophetic word that governs every detail of this night.</p>",
    "65": "<p>A fulfillment: &#8220;many other insulting things&#8221; echoes Ps 22:6&#8211;8&#8212;&#8220;I am a worm and not a man, scorned and despised&#8212;all who see me mock me, they hurl insults.&#8221; The Psalmic righteous sufferer&#8217;s experience of communal contempt reaches its ultimate instance in Christ. The shame he bears is the shame of the entire human condition taken up and endured by the one who is without shame before God.</p>",
    "66": "<p>A theme: the assembled council of elders, chief priests, and scribes bringing Jesus before them at daybreak enacts the pattern that Jesus himself had named: the Son of Man must be handed over to the chief priests and scribes, who will condemn him to death (Lk 9:22). Official Israel&#8217;s rejection of the Christ is not an accident or a tragedy; it is the fulfillment of the divine decree and the culmination of the long pattern of prophets rejected by their own people (Lk 13:34).</p>",
    "67": "<p>A direct revelation: &#8220;if I tell you, you will not believe me&#8212;and if I asked you, you would not answer.&#8221; Christ refuses to perform his identity on demand for those whose minds are already closed. He will not validate their framework&#8212;a Messiah who must prove himself to hostile judges. Instead he points them forward: they will see the vindication they refuse to believe now (v.69). Truth does not require the consent of those who have already decided against it.</p>",
    "68": "<p>A theme: &#8220;if I asked you, you would not answer&#8221;&#8212;Christ identifies the council&#8217;s unwillingness not just as unbelief but as a refusal of dialogue. The closed mind of official Israel at the moment of judgment is the judicial hardening that Jesus himself had described in parables (Lk 8:10). Those who have persistently refused the light are given over to the darkness they have chosen.</p>",
    "69": "<p>A direct revelation of God: &#8220;from now on, the Son of Man will be seated at the right hand of the mighty God.&#8221; At the moment of his earthly humiliation, Christ announces his heavenly exaltation. Ps 110:1 (the LORD says to my Lord: sit at my right hand) and Dan 7:13&#8211;14 (the Son of Man coming to the Ancient of Days) converge in this declaration: the condemned prisoner is the one who will be enthroned over all. His trial is the preamble to his coronation.</p>",
    "70": "<p>A direct revelation of God: &#8220;are you then the Son of God?&#8221; &#8212; &#8220;you say that I am.&#8221; Christ&#8217;s unambiguous affirmation before the Sanhedrin is the most explicit self-identification in Luke&#8217;s Gospel. The condemned one is the Son of God; the judge sitting over him is being judged by the one he judges. The irony is total: the council that condemns him for claiming to be the Son of God will one day stand before the Son of God whose claim was true.</p>",
    "71": "<p>A theme: &#8220;why do we need any more testimony? We have heard it from his own lips.&#8221; The terrible irony is complete: they use his truthful self-disclosure as the evidence for his condemnation. The very identity that constitutes his saving power (he is the Son of God, the enthroned Son of Man) is the claim they reject as blasphemy. Their verdict is their own condemnation: to call the Son of God a blasphemer is the deepest rejection possible.</p>"
  }
}

def main():
    existing = load_comm('mkt-christ', 'luke')
    merge_comm(existing, DATA)
    merge_comm(existing, FILL_CH22)
    save_comm('mkt-christ', 'luke', existing)
    total = sum(len(v) for v in existing.values())
    print(f"Luke mkt-christ: {len(existing)} chapters, {total} verses written.")

if __name__ == '__main__':
    main()
